values
  ('demo-observation-demo-observation-med-1', 'demo-hospitation-medikationsabgleich-entlassung', 1, 'Drei Medikationsstände liegen gleichzeitig vor', 'Vorbereitung eines Folgetermins zwei Tage nach Krankenhausentlassung.', 'Die MFA öffnet die Medikationsliste im PVS. Sie legt beide Ausdrucke neben den Bildschirm. Sie markiert drei abweichende Dosierungen auf Papier.', 'Befund / Dokumentation', 'fehlende Information', 'Fehleranfälligkeit', NULL, 'interpreted', NULL, NULL, ARRAY['MFA'::text, 'Hausärztin'::text, 'Patient'::text]::text[], ARRAY[]::text[], ARRAY['Medikationsabgleich'::text]::text[], '{"id":"demo-observation-demo-observation-med-1","sequence":1,"observedAt":"08:47 Uhr","title":"Drei Medikationsstände liegen gleichzeitig vor","situationContext":"Vorbereitung eines Folgetermins zwei Tage nach Krankenhausentlassung.","trigger":"Der Patient legt einen vorläufigen Entlassbrief und einen ausgedruckten Medikationsplan vor.","observed":"Die MFA öffnet die Medikationsliste im PVS. Sie legt beide Ausdrucke neben den Bildschirm. Sie markiert drei abweichende Dosierungen auf Papier.","actions":["Die MFA öffnet die Medikationsliste im PVS.","Sie legt beide Ausdrucke neben den Bildschirm.","Sie markiert drei abweichende Dosierungen auf Papier."],"toolsAndDocuments":["PVS","vorläufiger Entlassbrief","ausgedruckter Medikationsplan","Papiermarker"],"communicationChannels":[],"immediateConsequence":"Die Medikamentenliste wird vor dem Arztkontakt nicht aktualisiert.","affectedRoles":["MFA","Hausärztin","Patient"],"processPhase":"Befund / Dokumentation","problemType":"fehlende Information","impact":"Fehleranfälligkeit","currentWorkaround":"Abweichungen werden auf Papier markiert und der Ärztin vorgelegt.","settingType":"Hausarztpraxis","theme":"Medikationsabgleich","evidenceType":"interpreted","sourceType":"synthetic_demo_scenario","sourceReference":"Synthetischer Demo-Quellenhinweis 04 · https://demo-source-04.example.invalid/medikationssicherheit","uncertainty":"Die konkre